code = """import json

# Load READMEs
file_path_readmes = locals()['var_function-call-15164823336874266344']
with open(file_path_readmes, 'r') as f:
    readmes = json.load(f)

# Load Languages
file_path_langs = locals()['var_function-call-14529663143851951124']
with open(file_path_langs, 'r') as f:
    langs = json.load(f)

# Create a dictionary for repo languages
repo_langs = {item['repo_name']: item['language_description'] for item in langs}

# Identify non-Python repos
non_python_repos = set()
for repo, desc in repo_langs.items():
    if desc and "Python" not in desc:
        non_python_repos.add(repo)
    elif desc is None: 
        # If description is None, assume no python? 
        # The data shows "No language information available" as a string sometimes.
        # If desc is explicitly None, it's safe to assume we don't know, but likely no python if not detected.
        # But let's check the string "No language information available".
        # If the string doesn't contain "Python", it satisfies the condition.
        pass

# Filter READMEs
target_readmes = []
for r in readmes:
    if r['sample_repo_name'] in non_python_repos:
        target_readmes.append(r['content'])

# Count copyright
total = len(target_readmes)
copyright_count = 0
for content in target_readmes:
    if content and "copyright" in content.lower():
        copyright_count += 1

proportion = 0.0
if total > 0:
    proportion = copyright_count / total

print("__RESULT__:")
print(json.dumps({
    "total_non_python_readmes": total,
    "copyright_count": copyright_count,
    "proportion": proportion
}))"""

